   180→      const { data } = await q
   181→      const items = (data ?? []) as Record<string, unknown>[]
   182→      result[key] = nestedInclude
   183→        ? await Promise.all(items.map((item) => resolveIncludes(rel.table, item, nestedInclude)))
   184→        : items
